const express = require('express');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Twilio credentials
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// In-memory storage for SMS codes with session IDs
const smsCodes = {};

app.post('/send-sms', (req, res) => {
  const { phoneNumber } = req.body;
  if (!phoneNumber) return res.status(400).json({ error: 'Phone number is required' });

  // Generate a random 6-digit code
  const code = crypto.randomInt(100000, 999999);

  // Send the SMS code using Twilio
  client.messages.create({
    body: `Your verification code is ${code}`,
    from: 'your_twilio_phone_number',
    to: phoneNumber
  })
  .then(message => {
    const sessionId = crypto.randomBytes(16).toString('hex');
    smsCodes[sessionId] = { code, expiresAt: Date.now() + 300000 }; // Code expires in 5 minutes
    res.json({ sessionId });
  })
  .catch(error => {
    res.status(500).json({ error: 'Failed to send SMS' });
  });
});

app.post('/verify-code', (req, res) => {
  const { sessionId, code } = req.body;
  if (!sessionId || !code) return res.status(400).json({ error: 'Session ID and code are required' });

  const sessionCode = smsCodes[sessionId];
  if (!sessionCode) return res.status(401).json({ error: 'Invalid session ID' });
  if (Date.now() > sessionCode.expiresAt) return res.status(401).json({ error: 'Session expired' });
  if (code !== sessionCode.code) return res.status(401).json({ error: 'Incorrect code' });

  // Code is valid, clear the session
  delete smsCodes[sessionId];
  res.json({ message: 'Code verified successfully' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});